 82→        // 处理请求参数中“替换筛选”的参数
 83→        if (!empty($replace_filter)) {
 84→            $params = ReplaceFilterService::app()->replaceFilter($params, $replace_filter);
 85→        }
 86→
 87→        if (!empty($next_replace_filter)) {
 88→            $params = NextReplaceFilterService::app()->replaceFilter($params, $next_replace_filter);
 89→        }
 90→
 91→        // 处理请求参数中“授权”参数
 92→        if (!empty($authorize_config)) {
 93→            $token = AuthorizeService::app()->generateToken($authorize_config);
 94→            $params['authorized_token'] = $token;
 95→        }
 96→
 97→        // 有些接口是 stream response，这部分请求没办法用通用的 JSON 方式处理，所以这里直接转发，为了避免造成破坏性变更
 98→        // 这里只对部分接口进行特殊处理
 99→        if (!empty($response_format) && $response_format == 'stream') {
100→            // 如果同时有 ai_analysis_config，需要先拿完整响应再做 AI streaming
101→            if (!empty($ai_analysis_config) && !empty($ai_analysis_config['system_prompt'])) {
102→                $resp = $this->callBackendApi($action ?: $request->path(), $params);
103→                if (!empty($resp['data'])) {
104→                    $respData = &$resp['data'];
105→
106→                    // 解密
107→                    $decrypt_config = empty($respData['decrypt_config']) ? $decrypt_config : array_merge($decrypt_config ?? [], $respData['decrypt_config']);
108→                    if (isset($respData['decrypt_config'])) {
109→                        unset($respData['decrypt_config']);
110→                    }
111→                    if (!empty($decrypt_config)) {
112→                        $respData = DecryptService::app()->decryptData($respData, $decrypt_config, 'response');
113→                    }
114→
115→                    // 提取 AI 输入内容
116→                    $targetField = $ai_analysis_config['target_field'] ?? null;
117→                    $contentForAi = $targetField ? data_get($respData, $targetField, '') : json_encode($respData, JSON_UNESCAPED_UNICODE);
118→                    if (is_array($contentForAi)) {
119→                        $contentForAi = json_encode($contentForAi, JSON_UNESCAPED_UNICODE);
120→                    }
121→
122→                    $systemPrompt = $ai_analysis_config['system_prompt'];
123→                    $history = $ai_analysis_config['history'] ?? [];
124→
125→                    return response()->stream(function () use ($contentForAi, $systemPrompt, $history) {
126→                        AiAnalysisService::app()->analyzeStream(
127→                            $contentForAi,
128→                            $systemPrompt,
129→                            function (string $chunk) {
130→                                echo 'data: ' . json_encode([
131→                                    'error_code' => 0,
132→                                    'error_msg' => '',
133→                                    'data' => ['type' => 'chat', 'is_finished' => false, 'content' => $chunk],
134→                                ], JSON_UNESCAPED_UNICODE) . PHP_EOL . PHP_EOL;
135→                                ob_flush();
136→                                flush();
137→                            },
138→                            $history
139→                        );
140→                        // 结束帧
141→                        echo 'data: ' . json_encode([
142→                            'error_code' => 0,
143→                            'error_msg' => '',
144→                            'data' => ['type' => 'chat', 'is_finished' => true, 'content' => ''],
145→                        ], JSON_UNESCAPED_UNICODE) . PHP_EOL . PHP_EOL;
146→                        ob_flush();
147→                        flush();
148→                    }, 200, [
149→                        'Content-Type' => 'text/event-stream',
150→                        'Cache-Control' => 'no-cache',
151→                        'X-Accel-Buffering' => 'no',
152→                    ]);
153→                }
154→            }
155→
156→            // 原有的 stream 透传逻辑不变
157→            $resp = $this->callBackendApi($action ?: $request->path(), $params, true);
158→            return response()->stream(function () use ($resp) {
159→                $body = $resp->toPsrResponse()->getBody();
160→                $content = '';
161→                while (!$body->eof()) {
162→                    $bit = $body->read(1);
163→                    $content .= $bit;
164→                    if (substr($content, -2) == PHP_EOL.PHP_EOL) {
165→                        echo $content;
166→                        ob_flush();
167→                        flush();
168→                        $content = '';
169→                    }
170→                }
171→            }, $resp->status(), array_merge($resp->headers(), ['X-Accel-Buffering' => 'no']));
172→        }
173→
174→        $resp = $this->callBackendApi($action ?: $request->path(), $params);
175→        if (!empty($resp['data'])) {
176→            $respData = &$resp['data'];
177→            // 响应中有 decrypt_config 的话，与请求中的 decrypt_config 合并（相同键名以响应中的为准）
178→            $decrypt_config = empty($respData['decrypt_config']) ? $decrypt_config : array_merge($decrypt_config ?? [], $respData['decrypt_config']);
179→            if (isset($respData['decrypt_config'])) {
180→                unset($respData['decrypt_config']);
181→            }
182→            if (!empty($decrypt_config)) {
183→                $respData = DecryptService::app()->decryptData($respData, $decrypt_config, 'response');
184→            }
185→
186→            // AI 分析（解密之后执行，仅当 ai_analysis_config 存在时）
187→            if (!empty($ai_analysis_config) && !empty($ai_analysis_config['system_prompt'])) {
188→                $targetField = $ai_analysis_config['target_field'] ?? null;
189→                $outputField = $ai_analysis_config['output_field'] ?? 'ai_analysis';
190→                $contentForAi = $targetField ? data_get($respData, $targetField, '') : json_encode($respData, JSON_UNESCAPED_UNICODE);
191→
192→                if (is_array($contentForAi)) {
193→                    $contentForAi = json_encode($contentForAi, JSON_UNESCAPED_UNICODE);
194→                }
195→
196→                $aiResult = AiAnalysisService::app()->analyze(
197→                    $contentForAi,
198→                    $ai_analysis_config['system_prompt']
199→                );
200→                data_set($respData, $outputField, $aiResult);
201→            }
202→        }
203→
204→        return $resp;
205→    }
