207→    public function transferWithoutEncryptionProcess(Request $request, string $action = '', bool $retOrigResp = false): mixed
208→    {
209→        // 该请求不会做任何涉及到加解密的操作，直接转发即可，基于对三方的不信任，我们也不提供 hash/replace 之类的筛选
210→        $params = $request->all();
211→        $user = auth()->user()->getAuthIdentifier();
212→        $sfuser = SfuserMd::find($user);
213→        $params['sfuser_info'] = [
214→            'id' => $sfuser->id,
215→            'is_admin' => $sfuser->is_admin,
216→            'auth_source' => SfuserMd::AUTH_SOURCE_TOKEN,
217→            // 权限也一并不传递，尽力约束三方应用可以执行的操作
218→            'permissions' => [],
219→            'res_attrs' => [],
220→        ];
221→
222→        $fallbackSite = $sfuser->site;
223→        $site = $request->input('sys_site', $fallbackSite);
224→        // 如果 site 非法，使用我们默认的 site
225→        if (!in_array(strtoupper($site), config('my_sites.active_backend_sites'))) {
226→            $site = $fallbackSite;
227→        }
228→        SiteService::app()->setSite($site);
229→        $params['sys_lang'] = App::currentLocale();
230→        // 转发客户端 IP，以便后端某些接口针对 ip 进行过滤或者限流
231→        $params['client_ip'] = \Illuminate\Support\Facades\Request::ip();
232→
233→        $uri = $action ?: $request->path();
234→        if ($retOrigResp) {
235→            return ApiService::appWith('backend')->allowError()->sendRequest($uri, $params, ['stream' => true], true);
236→        }
237→
238→        return ApiService::appWith('backend')->allowError()->sendRequest($uri, $params);
239→    }
