267→        // 转发客户端 IP，以便后端某些接口针对 ip 进行过滤或者限流
268→        $params['client_ip'] = \Illuminate\Support\Facades\Request::ip();
269→
270→        if ($retOrigResp) {
271→            return ApiService::appWith('backend')->allowError()->sendRequest($uri, $params, ['stream' => true, 'timeout' => 1200], true);
